import React, { useEffect, useState } from 'react';
import { iotService } from '../api/dashboardServices';
import '../styles/ecoflow-3d-theme.css';

function IoTTelemetry() {
  const [loading, setLoading] = useState(true);
  const [telemetry, setTelemetry] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [selectedBin, setSelectedBin] = useState(null);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000); // Refresh every 5 seconds
    return () => clearInterval(interval);
  }, []);

  const loadData = async () => {
    try {
      const [telemetryData, alertsData] = await Promise.all([
        iotService.getTelemetry(),
        iotService.getSensorAlerts()
      ]);
      setTelemetry(telemetryData);
      setAlerts(alertsData);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'healthy': return 'success';
      case 'warning': return 'warning';
      case 'critical': return 'critical';
      default: return 'info';
    }
  };

  const filteredTelemetry = filter === 'all' 
    ? telemetry 
    : telemetry.filter(t => t.status === filter);

  return (
    <div className="page-header">
      <div>
        <h1 className="page-title">📡 Real-time IoT Telemetry</h1>
        <p className="page-subtitle">Live sensor monitoring and environmental data</p>
      </div>

      <div className="page-content">
        {loading ? (
          <div className="spinner" style={{ margin: '40px auto' }}></div>
        ) : (
          <>
            {/* Status Overview */}
            <div className="grid grid-4">
              <div className="card">
                <div className="card-header">
                  <div className="card-subtitle">Active Sensors</div>
                </div>
                <div style={{ fontSize: '36px', fontWeight: '700', marginTop: '8px', color: '#38ef7d' }}>
                  {telemetry.filter(t => t.status === 'healthy').length}
                </div>
                <div className="badge badge-success" style={{ marginTop: '8px' }}>Operational</div>
              </div>

              <div className="card">
                <div className="card-header">
                  <div className="card-subtitle">Warnings</div>
                </div>
                <div style={{ fontSize: '36px', fontWeight: '700', marginTop: '8px', color: '#ffd93d' }}>
                  {telemetry.filter(t => t.status === 'warning').length}
                </div>
                <div className="badge badge-warning" style={{ marginTop: '8px' }}>Monitor</div>
              </div>

              <div className="card">
                <div className="card-header">
                  <div className="card-subtitle">Critical</div>
                </div>
                <div style={{ fontSize: '36px', fontWeight: '700', marginTop: '8px', color: '#ff2244' }}>
                  {telemetry.filter(t => t.status === 'critical').length}
                </div>
                <div className="badge badge-critical" style={{ marginTop: '8px' }}>Urgent</div>
              </div>

              <div className="card">
                <div className="card-header">
                  <div className="card-subtitle">Active Alerts</div>
                </div>
                <div style={{ fontSize: '36px', fontWeight: '700', marginTop: '8px' }}>
                  {alerts.length}
                </div>
                <div className="badge badge-error" style={{ marginTop: '8px' }}>Events</div>
              </div>
            </div>

            {/* Alerts Feed */}
            {alerts.length > 0 && (
              <div style={{ marginTop: '32px' }}>
                <div className="card">
                  <div className="card-header">
                    <div className="card-title">🚨 Active Alerts</div>
                    <div className="badge badge-critical">{alerts.length}</div>
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                    {alerts.slice(0, 5).map((alert, idx) => (
                      <div key={idx} style={{ padding: '12px', background: 'rgba(255, 34, 68, 0.1)', border: '1px solid rgba(255, 34, 68, 0.3)', borderRadius: '8px' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
                          <div>
                            <div style={{ fontWeight: '600', color: '#ff2244' }}>⚠️ {alert.type}</div>
                            <div style={{ fontSize: '12px', color: '#a0b0c0', marginTop: '4px' }}>
                              Bin #{alert.bin_id} • {alert.message}
                            </div>
                          </div>
                          <button className="btn btn-danger btn-sm">Dismiss</button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {/* Telemetry Grid */}
            <div style={{ marginTop: '32px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                <div className="card-title">Live Sensor Data</div>
                <div style={{ display: 'flex', gap: '8px' }}>
                  {['all', 'healthy', 'warning', 'critical'].map(f => (
                    <button
                      key={f}
                      className={`btn btn-sm ${filter === f ? 'btn-accent' : 'btn-secondary'}`}
                      onClick={() => setFilter(f)}
                    >
                      {f.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>

              <div className="grid grid-3">
                {filteredTelemetry.map((bin, idx) => (
                  <div 
                    key={idx}
                    className="card interactive"
                    onClick={() => setSelectedBin(bin)}
                    style={{
                      borderColor: selectedBin?.id === bin.id ? '#00ff88' : 'rgba(0, 255, 136, 0.1)',
                      cursor: 'pointer'
                    }}
                  >
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '12px' }}>
                      <div style={{ fontSize: '20px', fontWeight: '700' }}>Bin #{bin.id}</div>
                      <span className={`badge badge-${getStatusBadge(bin.status)}`}>
                        {bin.status.toUpperCase()}
                      </span>
                    </div>

                    {/* Fill Level */}
                    <div style={{ marginBottom: '12px' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '6px' }}>
                        <span style={{ fontSize: '12px', color: '#a0b0c0' }}>Fill Level</span>
                        <span style={{ fontSize: '12px', fontWeight: '600' }}>{bin.fill_pct}%</span>
                      </div>
                      <div style={{ height: '6px', background: 'rgba(0, 255, 136, 0.1)', borderRadius: '3px', overflow: 'hidden' }}>
                        <div 
                          style={{
                            height: '100%',
                            background: `linear-gradient(90deg, #11998e, ${bin.fill_pct > 80 ? '#ff2244' : bin.fill_pct > 60 ? '#ffd93d' : '#38ef7d'})`,
                            width: `${bin.fill_pct}%`,
                            transition: 'width 0.3s'
                          }}
                        />
                      </div>
                    </div>

                    {/* Sensor Metrics */}
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', fontSize: '12px' }}>
                      <div>
                        <div style={{ color: '#a0b0c0' }}>Battery</div>
                        <div style={{ fontWeight: '600', marginTop: '2px', color: bin.battery_pct < 20 ? '#ff2244' : bin.battery_pct < 50 ? '#ffd93d' : '#38ef7d' }}>
                          {bin.battery_pct}%
                        </div>
                      </div>
                      <div>
                        <div style={{ color: '#a0b0c0' }}>Temp</div>
                        <div style={{ fontWeight: '600', marginTop: '2px' }}>
                          {bin.temperature}°C
                        </div>
                      </div>
                      <div>
                        <div style={{ color: '#a0b0c0' }}>Smoke</div>
                        <div style={{ fontWeight: '600', marginTop: '2px', color: bin.smoke_detected ? '#ff2244' : '#38ef7d' }}>
                          {bin.smoke_detected ? '⚠️ YES' : '✓ No'}
                        </div>
                      </div>
                      <div>
                        <div style={{ color: '#a0b0c0' }}>Tilt</div>
                        <div style={{ fontWeight: '600', marginTop: '2px', color: bin.tilt_detected ? '#ff2244' : '#38ef7d' }}>
                          {bin.tilt_detected ? '⚠️ YES' : '✓ No'}
                        </div>
                      </div>
                    </div>

                    {/* Last Update */}
                    <div style={{ marginTop: '12px', paddingTop: '12px', borderTop: '1px solid rgba(0, 255, 136, 0.1)', fontSize: '11px', color: '#a0b0c0' }}>
                      Updated: {new Date(bin.last_update).toLocaleTimeString()}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Selected Bin Details */}
            {selectedBin && (
              <div style={{ marginTop: '32px' }}>
                <div className="card">
                  <div className="card-header">
                    <div className="card-title">Bin #{selectedBin.id} - Detailed Telemetry</div>
                    <button 
                      className="btn btn-secondary btn-sm"
                      onClick={() => setSelectedBin(null)}
                    >
                      ✕ Close
                    </button>
                  </div>

                  <div className="grid grid-3">
                    <div style={{ padding: '16px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '12px', color: '#a0b0c0', textTransform: 'uppercase' }}>Fill Level</div>
                      <div style={{ fontSize: '32px', fontWeight: '700', marginTop: '8px' }}>{selectedBin.fill_pct}%</div>
                    </div>
                    <div style={{ padding: '16px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '12px', color: '#a0b0c0', textTransform: 'uppercase' }}>Battery</div>
                      <div style={{ fontSize: '32px', fontWeight: '700', marginTop: '8px', color: selectedBin.battery_pct < 20 ? '#ff2244' : '#38ef7d' }}>
                        {selectedBin.battery_pct}%
                      </div>
                    </div>
                    <div style={{ padding: '16px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '12px', color: '#a0b0c0', textTransform: 'uppercase' }}>Temperature</div>
                      <div style={{ fontSize: '32px', fontWeight: '700', marginTop: '8px' }}>{selectedBin.temperature}°C</div>
                    </div>
                  </div>

                  {/* GPS Location */}
                  {selectedBin.gps_lat && selectedBin.gps_lng && (
                    <div style={{ marginTop: '16px', padding: '16px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '12px', color: '#a0b0c0', textTransform: 'uppercase', marginBottom: '8px' }}>GPS Location</div>
                      <div style={{ fontFamily: 'monospace', fontSize: '12px', color: '#00ff88' }}>
                        {selectedBin.gps_lat.toFixed(6)}, {selectedBin.gps_lng.toFixed(6)}
                      </div>
                    </div>
                  )}

                  <button className="btn btn-accent" style={{ width: '100%', marginTop: '16px' }}>
                    📍 View on Map
                  </button>
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

export default IoTTelemetry;
